import React from "react";
import { useState } from "react";
import { useParams } from "react-router-dom";
import axios from "axios"
import { useEffect } from "react";


function DetailsPages(){
    const{id}=useParams()
    const [cities, setCities] = useState([])
    const [card, setCard] = useState([])
    
    useEffect(() => {
        axios.get(`http://localhost:4000/api/cities/${id}`)
        .then(response => setCard(response.data.response))
    }, [])
    
    // useEffect(() => {
    //     setCard(cities.filter(data => data._id === id))
    // }, [])

    // let card = cities.filter(data => data._id === id)
    console.log(card);
    console.log(id);
    return(
        <div className="card-container">
        {card.length > 0 && card.map((city, index) => (
            <div className="card" key={index}>
                <div className="image">
                <img className="image-card" src= {city.image} alt="cities" />
                </div>
                <div>
                    <h2>{city.cityname}</h2>
                    <h3>{city.country}</h3>
                    <p>{city.description}</p>
                </div>
            </div>
        ))}
        </div>
    );
}
export default DetailsPages
